INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES
(gen_random_uuid(), 'jo', 29, 1, NULL, 'R. A. Torrey em Jó 29:1', 'Na leitura de R. A. Torrey, vemos o chamado ao arrependimento, fé viva e missão. Jó 29 evidencia adoração, sabedoria e temor do Senhor como eixo da vida do povo de Deus, com ênfase em esperança escatológica. A passagem confronta o coração e organiza a prática diária do discípulo. Aplicação: submeta sua vontade à Palavra e caminhe em fidelidade.', 'R. A. Torrey', 'commentary', '#0E7490', NOW()),
(gen_random_uuid(), 'jo', 30, 1, NULL, 'Octavius Winslow em Jó 30:1', 'Segundo Octavius Winslow, a exposição textual com aplicação pastoral objetiva ilumina o sentido deste texto. Jó 30 mostra que adoração, sabedoria e temor do Senhor sustenta a caminhada da fé, especialmente em obediência da fé. A doutrina aqui conduz à devoção e à perseverança. Aplicação: firme-se nas promessas divinas e pratique a verdade com humildade.', 'Octavius Winslow', 'commentary', '#B45309', NOW()),
(gen_random_uuid(), 'jo', 31, 1, NULL, 'Heinrich Bullinger em Jó 31:1', 'Heinrich Bullinger destaca a centralidade das Escrituras e da graça soberana. Em Jó 31, o foco recai sobre adoração, sabedoria e temor do Senhor e chama a igreja para justiça com misericórdia. O texto orienta a fé para uma obediência concreta e perseverante. Aplicação: receba esta verdade com fé, arrependimento e esperança ativa.', 'Heinrich Bullinger', 'commentary', '#800080', NOW()),
(gen_random_uuid(), 'jo', 32, 1, NULL, 'Dwight L. Moody em Jó 32:1', 'Dwight L. Moody interpreta este versículo a partir de o chamado ao arrependimento, fé viva e missão. Em Jó 32, Deus revela adoração, sabedoria e temor do Senhor de forma pastoral e transformadora, promovendo perseverança na tribulação. A verdade bíblica forma caráter, culto e missão. Aplicação: responda com oração, disciplina espiritual e serviço cristão.', 'Dwight L. Moody', 'commentary', '#0E7490', NOW()),
(gen_random_uuid(), 'jo', 33, 1, NULL, 'Joseph Benson em Jó 33:1', 'Joseph Benson destaca a exposição textual com aplicação pastoral objetiva. Em Jó 33, o foco recai sobre adoração, sabedoria e temor do Senhor e chama a igreja para fidelidade na aliança. O texto orienta a fé para uma obediência concreta e perseverante. Aplicação: receba esta verdade com fé, arrependimento e esperança ativa.', 'Joseph Benson', 'commentary', '#B45309', NOW()),
(gen_random_uuid(), 'jo', 34, 1, NULL, 'Martin Bucer em Jó 34:1', 'Na leitura de Martin Bucer, vemos a centralidade das Escrituras e da graça soberana. Jó 34 evidencia adoração, sabedoria e temor do Senhor como eixo da vida do povo de Deus, com ênfase em arrependimento sincero. A passagem confronta o coração e organiza a prática diária do discípulo. Aplicação: submeta sua vontade à Palavra e caminhe em fidelidade.', 'Martin Bucer', 'commentary', '#800080', NOW()),
